4: import { getFeatureOptInService } from "@calcom/features/di/containers/FeatureOptInService";
5: import { TeamRepository } from "@calcom/features/ee/teams/repositories/TeamRepository";
6: import { isOptInFeature } from "@calcom/features/feature-opt-in/config";
7: import { FeaturesRepository } from "@calcom/features/flags/features.repository";
8: import { MembershipRepository } from "@calcom/features/membership/repositories/MembershipRepository";
9: import { prisma } from "@calcom/prisma";
10: 
11: import { TRPCError } from "@trpc/server";
12: 
13: import authedProcedure from "../../../procedures/authedProcedure";
14: import { router } from "../../../trpc";
15: import { createOrgPbacProcedure, createTeamPbacProcedure } from "../../../procedures/pbacProcedures";
16: 
17: const featureStateSchema: ZodEnum<["enabled", "disabled", "inherit"]> = z.enum(["enabled", "disabled", "inherit"]);
18: 
19: const featureOptInService = getFeatureOptInService();
20: const featuresRepository = new FeaturesRepository(prisma);
21: const teamRepository = new TeamRepository(prisma);
22: 
23: /**
24:  * Helper to get user's org and team IDs from their memberships.
25:  * Returns orgId (if user belongs to an org) and teamIds (non-org teams).
26:  */
27: async function getUserOrgAndTeamIds(userId: number): Promise<{ orgId: number | null; teamIds: number[] }> {
28:   const memberships = await MembershipRepository.findAllByUserId({
29:     userId,
30:     filters: { accepted: true },
31:   });
32: 
33:   let orgId: number | null = null;
34:   const teamIds: number[] = [];
35: 
36:   for (const membership of memberships) {
37:     if (membership.team.isOrganization) {
38:       orgId = membership.teamId;
39:     } else {
40:       teamIds.push(membership.teamId);
41:     }
42:   }
43: 
44:   return { orgId, teamIds };
45: }
46: 
47: export const featureOptInRouter = router({
48:   /**
49:    * Get all opt-in features with states for current user.
50:    * This considers all teams/orgs the user belongs to.
51:    */
52:   listForUser: authedProcedure.query(async ({ ctx }) => {
53:     const { orgId, teamIds } = await getUserOrgAndTeamIds(ctx.user.id);
54: 
55:     return featureOptInService.listFeaturesForUser({
56:       userId: ctx.user.id,
57:       orgId,
58:       teamIds,
59:     });
60:   }),
61: 
62:   /**
63:    * Get all opt-in features with states for a team settings page.
64:    * Used by team admins to configure feature opt-in for their team.
65:    * Also returns the organization state if the team belongs to an organization.
66:    */
67:   listForTeam: createTeamPbacProcedure("featureOptIn.read").query(async ({ input }) => {
68:     // Get the team's parent organization ID (if any)
69:     const parentOrg = await teamRepository.findParentOrganizationByTeamId(input.teamId);
70:     const parentOrgId = parentOrg?.id ?? null;
71: 
72:     return featureOptInService.listFeaturesForTeam({ teamId: input.teamId, parentOrgId, scope: "team" });
73:   }),
74: 
75:   /**
76:    * Get all opt-in features with states for organization settings page.
77:    * Used by org admins to configure feature opt-in for their organization.
78:    */
79:   listForOrganization: createOrgPbacProcedure("featureOptIn.read").query(async ({ ctx }) => {
80:     // Organizations use the same listFeaturesForTeam since they're stored in TeamFeatures
81:     // Pass scope: "org" to filter features that are scoped to organizations
82:     return featureOptInService.listFeaturesForTeam({ teamId: ctx.organizationId, scope: "org" });
83:   }),
84: 
85:   /**
86:    * Set user's feature state.
87:    */
88:   setUserState: authedProcedure
89:     .input(
90:       z.object({
91:         slug: z.string(),
92:         state: featureStateSchema,
93:       })
94:     )
95:     .mutation(async ({ ctx, input }) => {
96:       if (!isOptInFeature(input.slug)) {
97:         throw new TRPCError({
98:           code: "BAD_REQUEST",
99:           message: "Invalid slug. This feature is not opt-in configurable.",
100:         });
101:       }
102: 
103:       await featureOptInService.setUserFeatureState({
104:         userId: ctx.user.id,
105:         featureId: input.slug,
106:         state: input.state,
107:         assignedBy: ctx.user.id,
108:       });
109: 
110:       return { success: true };
111:     }),
112: 
113:   /**
114:    * Set team's feature state (requires team admin).
115:    */
116:   setTeamState: createTeamPbacProcedure("featureOptIn.update")
117:     .input(
118:       z.object({
119:         slug: z.string(),
120:         state: featureStateSchema,
121:       })
122:     )
123:     .mutation(async ({ ctx, input }) => {
124:       if (!isOptInFeature(input.slug)) {
125:         throw new TRPCError({
126:           code: "BAD_REQUEST",
127:           message: "Invalid slug. This feature is not opt-in configurable.",
128:         });
129:       }
130: 
131:       await featureOptInService.setTeamFeatureState({
132:         teamId: input.teamId,
133:         featureId: input.slug,
134:         state: input.state,
135:         assignedBy: ctx.user.id,
136:         scope: "team",
137:       });
138: 
139:       return { success: true };
140:     }),
141: 
142:   /**
143:    * Set organization's feature state (requires org admin).
144:    */
145:   setOrganizationState: createOrgPbacProcedure("featureOptIn.update")
146:     .input(
147:       z.object({
148:         slug: z.string(),
149:         state: featureStateSchema,
150:       })
151:     )
152:     .mutation(async ({ ctx, input }) => {
153:       if (!isOptInFeature(input.slug)) {
154:         throw new TRPCError({
155:           code: "BAD_REQUEST",
156:           message: "Invalid slug. This feature is not opt-in configurable.",
157:         });
158:       }
159: 
160:       // Organizations use the same TeamFeatures table
161:       await featureOptInService.setTeamFeatureState({
162:         teamId: ctx.organizationId,
163:         featureId: input.slug,
164:         state: input.state,
165:         assignedBy: ctx.user.id,
166:         scope: "org",
167:       });
168: 
169:       return { success: true };
170:     }),
171: 
172:   /**
173:    * Get user's auto opt-in preference.
174:    */
175:   getUserAutoOptIn: authedProcedure.query(async ({ ctx }) => {
176:     const autoOptIn = await featuresRepository.getUserAutoOptIn(ctx.user.id);
177:     return { autoOptIn };
178:   }),
179: 
180:   /**
181:    * Set user's auto opt-in preference.
182:    */
183:   setUserAutoOptIn: authedProcedure
184:     .input(
185:       z.object({
186:         autoOptIn: z.boolean(),
187:       })
188:     )
189:     .mutation(async ({ ctx, input }) => {
190:       await featuresRepository.setUserAutoOptIn(ctx.user.id, input.autoOptIn);
191:       return { success: true };
192:     }),
193: 
194:   /**
195:    * Get team's auto opt-in preference (requires team admin).
196:    */
197:   getTeamAutoOptIn: createTeamPbacProcedure("featureOptIn.read").query(async ({ input }) => {
198:     const result = await featuresRepository.getTeamsAutoOptIn([input.teamId]);
199:     return { autoOptIn: result[input.teamId] ?? false };
200:   }),
201: 
202:   /**
203:    * Set team's auto opt-in preference (requires team admin).
204:    */
205:   setTeamAutoOptIn: createTeamPbacProcedure("featureOptIn.update")
206:     .input(
207:       z.object({
208:         autoOptIn: z.boolean(),
209:       })
210:     )
211:     .mutation(async ({ input }) => {
212:       await featuresRepository.setTeamAutoOptIn(input.teamId, input.autoOptIn);
213:       return { success: true };
214:     }),
215: 
216:   /**
217:    * Get organization's auto opt-in preference (requires org admin).
218:    */
219:   getOrganizationAutoOptIn: createOrgPbacProcedure("featureOptIn.read").query(async ({ ctx }) => {
220:     const result = await featuresRepository.getTeamsAutoOptIn([ctx.organizationId]);
221:     return { autoOptIn: result[ctx.organizationId] ?? false };
222:   }),
223: 
224:   /**
225:    * Set organization's auto opt-in preference (requires org admin).
226:    */
227:   setOrganizationAutoOptIn: createOrgPbacProcedure("featureOptIn.update")
228:     .input(
229:       z.object({
230:         autoOptIn: z.boolean(),
231:       })
232:     )
233:     .mutation(async ({ ctx, input }) => {
234:       await featuresRepository.setTeamAutoOptIn(ctx.organizationId, input.autoOptIn);
235:       return { success: true };
